const startedAt = new Date().toISOString();
const logId = $input.first().json[0]?.id || $input.first().json?.id;
return [{ json: { log_id: logId, started_at: startedAt } }];

// Define brands with their Klaviyo API keys
// All 3 brands use the same Klaviyo account/key for now
const brands = [
  { brand_id: 1, brand_name: 'spa', api_key: $env.KLAVIYO_API_KEY },
  { brand_id: 2, brand_name: 'aesthetics', api_key: $env.KLAVIYO_API_KEY },
  { brand_id: 3, brand_name: 'slimming', api_key: $env.KLAVIYO_API_KEY }
];

const logId = $input.first().json.log_id;
const startedAt = $input.first().json.started_at;

return brands.map(b => ({ json: { ...b, log_id: logId, started_at: startedAt } }));

const brandId = $('Build Brand List').item.json.brand_id;
const campaigns = $input.first().json.data || [];

if (campaigns.length === 0) {
  return [{ json: { brand_id: brandId, campaign_ids: [], campaigns: [], skip: true } }];
}

const campaignIds = campaigns.map(c => c.id);
const campaignMeta = campaigns.map(c => ({
  id: c.id,
  name: c.attributes?.name || 'Unknown',
  send_time: c.attributes?.send_time || c.attributes?.created_at
}));

return [{ json: { brand_id: brandId, campaign_ids: campaignIds, campaigns: campaignMeta, skip: false } }];

const brandId = $('Extract Campaign IDs').item.json.brand_id;
const campaigns = $('Extract Campaign IDs').item.json.campaigns;
const metricsData = $input.first().json.data || [];

const rows = [];

// Build a map of metrics by campaign ID
const metricsMap = {};
for (const entry of metricsData) {
  const stats = entry.attributes?.statistics || {};
  const cId = entry.relationships?.campaign?.data?.id || entry.id;
  metricsMap[cId] = stats;
}

// Group by date to compute revenue_pct_of_total
const byDate = {};

for (const campaign of campaigns) {
  const sendDate = campaign.send_time ? campaign.send_time.substring(0, 10) : new Date().toISOString().substring(0, 10);
  const metrics = metricsMap[campaign.id] || {};

  const row = {
    date: sendDate,
    brand_id: brandId,
    campaign_name: campaign.name,
    sends: metrics.recipients || 0,
    opens: metrics.opens || 0,
    clicks: metrics.clicks || 0,
    revenue: parseFloat(metrics.revenue || 0).toFixed(2)
  };

  if (!byDate[sendDate]) byDate[sendDate] = [];
  byDate[sendDate].push(row);
  rows.push(row);
}

// Compute revenue_pct_of_total per date
for (const date of Object.keys(byDate)) {
  const dateRows = byDate[date];
  const totalRevenue = dateRows.reduce((sum, r) => sum + parseFloat(r.revenue), 0);
  for (const row of dateRows) {
    row.revenue_pct_of_total = totalRevenue > 0
      ? parseFloat((parseFloat(row.revenue) / totalRevenue * 100).toFixed(2))
      : 0;
  }
}

return rows.map(r => ({ json: r }));

const logId = $('Extract Log ID').first().json.log_id;
const startedAt = $('Extract Log ID').first().json.started_at;
const items = $input.all();
const rowsUpserted = items.length;
const durationSec = Math.round((Date.now() - new Date(startedAt).getTime()) / 1000);

return [{ json: { log_id: logId, rows_upserted: rowsUpserted, duration_sec: durationSec } }];

const errorMsg = $input.first().json.execution?.error?.message || 'Unknown error';
let logId = null;
try {
  const execData = $input.first().json.execution?.data?.resultData?.runData;
  if (execData && execData['Extract Log ID']) {
    logId = execData['Extract Log ID'][0]?.data?.main?.[0]?.[0]?.json?.log_id;
  }
} catch(e) {}

return [{ json: { log_id: logId, error_message: errorMsg.substring(0, 1000) } }];
